sourcesContent:
/**
 * Application Form Component
 *
 * Dynamic multi-step wizard for applicants to apply for credentials.
 * Dynamically renders fields based on credential configuration's
 * required_fields, optional_fields, and custom_fields.
 */

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import {
  Box,
  Container,
  Paper,
  Typography,
  Button,
  Stepper,
  Step,
  StepLabel,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Grid,
  Card,
  CardContent,
  Alert,
  CircularProgress,
  Checkbox,
  FormControlLabel,
  Chip,
  Avatar,
  Fade,
  List,
  ListItem,
  ListItemText,
} from '@mui/material';
import ArrowBackIcon from '@mui/icons-material/ArrowBack';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import PhotoCameraIcon from '@mui/icons-material/PhotoCamera';
import DeleteIcon from '@mui/icons-material/Delete';
import UploadFileIcon from '@mui/icons-material/UploadFile';
import { useAuth } from '../../hooks/useAuth';
import { DynamicFieldRenderer, DynamicFieldGroup } from './DynamicFieldRenderer';


const API_URL = process.env.REACT_APP_API_URL || '';

/**
 * Group fields into logical steps based on their names/prefixes
 */
function groupFieldsIntoSteps(requiredFields = [], optionalFields = [], customFields = []) {
  const steps = [];

  // Define standard field categories
  const personalFields = ['first_name', 'last_name', 'family_name', 'given_name', 'date_of_birth', 'birth_date', 'email', 'phone', 'nationality', 'sex', 'gender'];
  const addressFields = ['street', 'city', 'state', 'zip', 'postal_code', 'country', 'address'];
  const documentFields = ['document_number', 'license_class', 'driving_privileges', 'restrictions', 'issue_date', 'expiry_date'];
  const photoFields = ['portrait', 'signature', 'photo'];

  const allFields = [
    ...requiredFields.map(f => ({ name: typeof f === 'string' ? f : f.name, required: true, ...f })),
    ...optionalFields.map(f => ({ name: typeof f === 'string' ? f : f.name, required: false, ...f })),
    ...customFields.map(f => ({ name: f.name, required: false, ...f })),
  ];

  // Categorize fields
  const personal = allFields.filter(f => personalFields.some(pf => f.name.toLowerCase().includes(pf)));
  const address = allFields.filter(f => addressFields.some(af => f.name.toLowerCase().includes(af)));
  const document = allFields.filter(f => documentFields.some(df => f.name.toLowerCase().includes(df)));
  const photo = allFields.filter(f => photoFields.some(pf => f.name.toLowerCase().includes(pf)));
  const other = allFields.filter(f => 
    !personal.includes(f) && 
    !address.includes(f) && 
    !document.includes(f) && 
    !photo.includes(f)
  );

  if (personal.length > 0) steps.push({ label: 'Personal Information', fields: personal });
  if (address.length > 0) steps.push({ label: 'Address', fields: address });
  if (document.length > 0) steps.push({ label: 'Document Details', fields: document });
  if (other.length > 0) steps.push({ label: 'Additional Information', fields: other });
  if (photo.length > 0) steps.push({ label: 'Photos & Documents', fields: photo });
  steps.push({ label: 'Review & Submit', fields: [] });

  return steps;
}

export default function ApplicationForm() {
  const { credentialType: credentialConfigId } = useParams();
  const navigate = useNavigate();
  const location = useLocation();
  const { user, organizationId } = useAuth();
  const fileInputRefs = useRef({});

  const [activeStep, setActiveStep] = useState(0);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState(null);
  const [submitted, setSubmitted] = useState(false);
  const [applicationId, setApplicationId] = useState(null);
  const [credentialConfig, setCredentialConfig] = useState(
    location.state?.credential || null
  );
  const [configLoading, setConfigLoading] = useState(false);

  // Dynamic form data (keys based on credential config)
  const [formData, setFormData] = useState({
    acceptTerms: false,
  });

  // Validation errors
  const [validationErrors, setValidationErrors] = useState({});

  // Compute steps dynamically from credential config
  const steps = useMemo(() => {
    if (!credentialConfig) return [{ label: 'Review & Submit', fields: [] }];

    return groupFieldsIntoSteps(
      credentialConfig.required_fields || [],
      credentialConfig.optional_fields || [],
      credentialConfig.custom_fields || []
    );
  }, [credentialConfig]);

  // Flatten all fields for validation
  const allFields = useMemo(() => {
    return steps.slice(0, -1).flatMap(step => step.fields);
  }, [steps]);

  const requiredFieldNames = useMemo(() => {
    return allFields.filter(f => f.required).map(f => f.name);
  }, [allFields]);

  const fetchApplicantById = async (applicantId) => {
    if (!applicantId) {
      return null;
    }

    const response = await fetch(`${API_URL}/api/applicants/${applicantId}`, {
      credentials: 'include',
    });

    if (!response.ok) {
      return null;
    }

    const data = await response.json();
    return data?.id || null;
  };

  const fetchApplicantByUser = async () => {
    if (!user?.user_id) {
      return null;
    }

    const response = await fetch(`${API_URL}/api/applicants/by-user/${user.user_id}`, {
      credentials: 'include',
    });

    if (!response.ok) {
      return null;
    }

    const data = await response.json();
    return data?.id || null;
  };

  const resolveApplicantId = async () => {
    const byId = await fetchApplicantById(user?.applicant_id);
    if (byId) {
      return byId;
    }

    const byUser = await fetchApplicantByUser();
    return byUser || null;
  };

  const createApplicant = async (address) => {
    if (!user?.user_id) {
      throw new Error('Unable to resolve applicant profile');
    }

    const response = await fetch(`${API_URL}/api/applicants`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({
        user_id: user.user_id,
        given_name: formData.firstName,
        family_name: formData.lastName,
        email: formData.email || user.email,
        date_of_birth: formData.dateOfBirth,
        nationality: 'USA',
        address,
      }),
    });

    if (!response.ok) {
      const data = await response.json();
      throw new Error(data.detail || 'Failed to create applicant');
    }

    const data = await response.json();
    return data?.id || null;
  };

  const readFileAsBase64 = (file) =>
    new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => {
        const result = reader.result;
        if (typeof result !== 'string') {
          resolve(null);
          return;
        }
        const [, base64] = result.split(',');
        resolve(base64 || null);
      };
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });

  useEffect(() => {
    const fetchCredentialConfig = async () => {
      if (!credentialConfigId || credentialConfig) {
        return;
      }
      if (!organizationId) {
        setError('Organization context missing for credential configuration.');
        return;
      }
      setConfigLoading(true);
      try {
        const response = await fetch(
          `${API_URL}/api/organizations/${organizationId}/credential-types/${credentialConfigId}`,
          { credentials: 'include' }
        );
        if (!response.ok) {
          throw new Error('Unable to load credential configuration');
        }
        const data = await response.json();
        setCredentialConfig(data.credential_type || null);
      } catch (err) {
        setError(err.message);
      } finally {
        setConfigLoading(false);
      }
    };

    fetchCredentialConfig();
  }, [credentialConfigId, credentialConfig, organizationId]);

  useEffect(() => {
    // Pre-fill user email if email field exists
    if (user?.email && allFields.some(f => f.name === 'email')) {
      setFormData(prev => ({ ...prev, email: user.email }));
    }
  }, [user, allFields]);

  const handleFieldChange = (fieldName, value) => {
    setFormData(prev => ({
      ...prev,
      [fieldName]: value
    }));
    // Clear validation error when field is edited
    if (validationErrors[fieldName]) {
      setValidationErrors(prev => ({ ...prev, [fieldName]: null }));
    }
  };

  const validateStep = (step) => {
    const errors = {};

    switch (step) {
      case 0: // Personal Info
        if (!formData.firstName.trim()) errors.firstName = 'First name is required';
        if (!formData.lastName.trim()) errors.lastName = 'Last name is required';
        if (!formData.dateOfBirth) errors.dateOfBirth = 'Date of birth is required';
        if (!formData.email.trim()) errors.email = 'Email is required';
        break;

      case 1: // Address
        if (!formData.street.trim()) errors.street = 'Street address is required';
        if (!formData.city.trim()) errors.city = 'City is required';
        if (!formData.state) errors.state = 'State is required';
        if (!formData.zip.trim()) errors.zip = 'ZIP code is required';
        if (formData.zip && !/^\d{5}(-\d{4})?$/.test(formData.zip)) {
          errors.zip = 'Invalid ZIP code format';
        }
        break;

      case 2: // License Details
        if (!formData.licenseClass) errors.licenseClass = 'License class is required';
        if (!formData.documentNumber.trim()) errors.documentNumber = 'Document number is required';
        break;

      case 3: // Photo
        if (!formData.portrait) errors.portrait = 'Portrait photo is required';
        break;

      case 4: // Review
        if (!formData.acceptTerms) errors.acceptTerms = 'You must accept the terms';
        break;

      default:
        break;
    }

    setValidationErrors(errors);
    return Object.keys(errors).length === 0;
  };

  const handleNext = () => {
    if (validateStep(activeStep)) {
      setActiveStep(prev => prev + 1);
    }
  };

  const handleBack = () => {
    setActiveStep(prev => prev - 1);
  };

  const handleSubmit = async () => {
    if (!validateStep(activeStep)) return;

    setSubmitting(true);
    setError(null);

    try {
      if (!credentialConfig?.id && !credentialConfigId) {
        throw new Error('Please select a credential to apply for.');
      }
      const address = {
        street_line1: formData.street,
        city: formData.city,
        state_province: formData.state,
        postal_code: formData.zip,
        country: 'USA',
      };

      let applicantId = await resolveApplicantId();
      let applicantCreated = false;

      if (!applicantId) {
        applicantId = await createApplicant(address);
        applicantCreated = true;
      }

      if (!applicantId) {
        throw new Error('Unable to resolve applicant profile');
      }

      if (!applicantCreated) {
        const updateResponse = await fetch(`${API_URL}/api/applicants/${applicantId}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({
            given_name: formData.firstName,
            family_name: formData.lastName,
            address,
          }),
        });

        if (!updateResponse.ok) {
          if (updateResponse.status === 404) {
            const fallbackApplicantId = await fetchApplicantByUser();
            if (fallbackApplicantId) {
              applicantId = fallbackApplicantId;
            } else {
              applicantId = await createApplicant(address);
              applicantCreated = true;
            }
            if (!applicantId) {
              throw new Error('Unable to resolve applicant profile');
            }
          } else {
            const data = await updateResponse.json();
            throw new Error(data.detail || 'Failed to update applicant');
          }
        }
      }

      const createResponse = await fetch(`${API_URL}/api/applicants/applications`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({
          applicant_id: applicantId,
          credential_configuration_id: credentialConfig?.id || credentialConfigId,
          issuing_authority: 'Marty Trust Services',
          requested_validity_years: 10,
          metadata: {
            document_number: formData.documentNumber,
            credential_type: credentialConfig?.credentialType || credentialConfig?.credential_type,
            credential_display_name: credentialConfig?.name || credentialConfig?.display_name,
            license_class: formData.licenseClass,
            restrictions: formData.restrictions,
          },
        }),
      });

      if (!createResponse.ok) {
        const data = await createResponse.json();
        throw new Error(data.detail || 'Failed to create application');
      }

      const created = await createResponse.json();

      const submitResponse = await fetch(
        `${API_URL}/api/applicants/applications/${created.id}/submit`,
        {
          method: 'POST',
          credentials: 'include',
        }
      );

      if (!submitResponse.ok) {
        const data = await submitResponse.json();
        throw new Error(data.detail || 'Failed to submit application');
      }

      const submittedApplication = await submitResponse.json();

      const imageBase64 = formData.portrait
        ? await readFileAsBase64(formData.portrait)
        : null;
      const templateBase64 = imageBase64 || btoa('test-biometric-template');

      const biometricResponse = await fetch(
        `${API_URL}/api/applicants/${applicantId}/biometrics`,
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({
            biometric_type: 'FACIAL',
            template_data_base64: templateBase64,
            image_data_base64: imageBase64,
            is_live_capture: true,
            capture_device_id: 'web-form',
          }),
        }
      );

      if (!biometricResponse.ok) {
        const data = await biometricResponse.json();
        throw new Error(data.detail || 'Failed to enroll biometric');
      }

      setApplicationId(submittedApplication.id);
      setSubmitted(true);

      // Redirect after delay
      setTimeout(() => {
        navigate('/my-applications');
      }, 5000);
    } catch (err) {
      console.error('Error submitting application:', err);
      setError(err.message);
    } finally {
      setSubmitting(false);
    }
  };

  const renderPersonalInfoStep = () => (
    <Box data-testid="personal-info-step">
      <Typography variant="h6" gutterBottom>
        Personal Information
      </Typography>
      <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
        Enter your personal details as they appear on your government-issued ID.
      </Typography>

      <Grid container spacing={3}>
        <Grid item xs={12} md={6}>
          <TextField
            fullWidth
            required
            label="First Name"
            value={formData.firstName}
            onChange={handleInputChange('firstName')}
            error={!!validationErrors.firstName}
            helperText={validationErrors.firstName}
            data-testid="first-name-input"
          />
        </Grid>
        <Grid item xs={12} md={6}>
          <TextField
            fullWidth
            required
            label="Last Name"
            value={formData.lastName}
            onChange={handleInputChange('lastName')}
            error={!!validationErrors.lastName}
            helperText={validationErrors.lastName}
            data-testid="last-name-input"
          />
        </Grid>
        <Grid item xs={12} md={6}>
          <TextField
            fullWidth
            required
            type="date"
            label="Date of Birth"
            value={formData.dateOfBirth}
            onChange={handleInputChange('dateOfBirth')}
            error={!!validationErrors.dateOfBirth}
            helperText={validationErrors.dateOfBirth}
            InputLabelProps={{ shrink: true }}
            data-testid="dob-input"
          />
        </Grid>
        <Grid item xs={12} md={6}>
          <TextField
            fullWidth
            required
            type="email"
            label="Email Address"
            value={formData.email}
            onChange={handleInputChange('email')}
            error={!!validationErrors.email}
            helperText={validationErrors.email}
            data-testid="email-input"
          />
        </Grid>
      </Grid>
    </Box>
  );

  const renderAddressStep = () => (
    <Box data-testid="address-step">
      <Typography variant="h6" gutterBottom>
        Residential Address
      </Typography>
      <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
        Enter your current residential address.
      </Typography>

      <Grid container spacing={3}>
        <Grid item xs={12}>
          <TextField
            fullWidth
            required
            label="Street Address"
            value={formData.street}
            onChange={handleInputChange('street')}
            error={!!validationErrors.street}
            helperText={validationErrors.street}
            data-testid="street-input"
          />
        </Grid>
        <Grid item xs={12} md={5}>
          <TextField
            fullWidth
            required
            label="City"
            value={formData.city}
            onChange={handleInputChange('city')}
            error={!!validationErrors.city}
            helperText={validationErrors.city}
            data-testid="city-input"
          />
        </Grid>
        <Grid item xs={12} md={4}>
          <FormControl fullWidth required error={!!validationErrors.state}>
            <InputLabel>State</InputLabel>
            <Select
              value={formData.state}
              onChange={handleInputChange('state')}
              label="State"
              data-testid="state-select"
            >
              {US_STATES.map(s => (
                <MenuItem key={s.value} value={s.value}>{s.label}</MenuItem>
              ))}
            </Select>
          </FormControl>
        </Grid>
        <Grid item xs={12} md={3}>
          <TextField
            fullWidth
            required
            label="ZIP Code"
            value={formData.zip}
            onChange={handleInputChange('zip')}
            error={!!validationErrors.zip}
            helperText={validationErrors.zip}
            data-testid="zip-input"
          />
        </Grid>
      </Grid>
    </Box>
  );

  const renderLicenseStep = () => (
    <Box data-testid="license-step">
      <Typography variant="h6" gutterBottom>
        License Details
      </Typography>
      <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
        Enter your driving license information.
      </Typography>

      <Grid container spacing={3}>
        <Grid item xs={12} md={6}>
          <FormControl fullWidth required error={!!validationErrors.licenseClass}>
            <InputLabel>License Class</InputLabel>
            <Select
              value={formData.licenseClass}
              onChange={handleInputChange('licenseClass')}
              label="License Class"
              data-testid="license-class-select"
            >
              {LICENSE_CLASSES.map(lc => (
                <MenuItem key={lc.value} value={lc.value}>{lc.label}</MenuItem>
              ))}
            </Select>
          </FormControl>
        </Grid>
        <Grid item xs={12} md={6}>
          <TextField
            fullWidth
            required
            label="Document Number"
            value={formData.documentNumber}
            onChange={handleInputChange('documentNumber')}
            error={!!validationErrors.documentNumber}
            helperText={validationErrors.documentNumber || 'Your current license number'}
            data-testid="document-number-input"
          />
        </Grid>
        <Grid item xs={12}>
          <TextField
            fullWidth
            label="Restrictions (if any)"
            value={formData.restrictions}
            onChange={handleInputChange('restrictions')}
            placeholder="e.g., Corrective lenses required"
            data-testid="restrictions-input"
          />
        </Grid>
      </Grid>
    </Box>
  );

  const renderPhotoStep = () => (
    <Box data-testid="photo-step">
      <Typography variant="h6" gutterBottom>
        Portrait Photo
      </Typography>
      <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
        Upload a recent passport-style photo. Face must be clearly visible with neutral expression.
      </Typography>

      <Grid container spacing={3}>
        <Grid item xs={12} md={6}>
          <Card variant="outlined" sx={{ p: 3, textAlign: 'center' }}>
            {formData.portraitPreview ? (
              <Box>
                <Avatar
                  src={formData.portraitPreview}
                  sx={{ width: 150, height: 150, mx: 'auto', mb: 2 }}
                  data-testid="photo-preview"
                />
                <Button
                  variant="outlined"
                  color="error"
                  startIcon={<DeleteIcon />}
                  onClick={handleRemovePhoto}
                  sx={{ mr: 1 }}
                >
                  Remove
                </Button>
                <Button
                  variant="outlined"
                  startIcon={<PhotoCameraIcon />}
                  onClick={() => fileInputRef.current?.click()}
                >
                  Change
                </Button>
              </Box>
            ) : (
              <Box>
                <Avatar sx={{ width: 150, height: 150, mx: 'auto', mb: 2, bgcolor: 'grey.200' }}>
                  <PhotoCameraIcon sx={{ fontSize: 60, color: 'grey.400' }} />
                </Avatar>
                <Button
                  variant="contained"
                  startIcon={<UploadFileIcon />}
                  onClick={() => fileInputRef.current?.click()}
                >
                  Upload Photo
                </Button>
              </Box>
            )}
            <input
              ref={fileInputRef}
              type="file"
              accept="image/*"
              hidden
              onChange={handlePhotoUpload}
              data-testid="portrait-upload-input"
            />
            {validationErrors.portrait && (
              <Alert severity="error" sx={{ mt: 2 }}>
                {validationErrors.portrait}
              </Alert>
            )}
          </Card>
        </Grid>
        <Grid item xs={12} md={6}>
          <Card variant="outlined" sx={{ p: 2 }}>
            <Typography variant="subtitle2" gutterBottom>
              Photo Requirements:
            </Typography>
            <List dense>
              <ListItem>
                <ListItemText primary="• Clear, focused image" />
              </ListItem>
              <ListItem>
                <ListItemText primary="• Full face visible, eyes open" />
              </ListItem>
              <ListItem>
                <ListItemText primary="• Neutral expression" />
              </ListItem>
              <ListItem>
                <ListItemText primary="• Plain white or light background" />
              </ListItem>
              <ListItem>
                <ListItemText primary="• No hats or head coverings (except religious)" />
              </ListItem>
              <ListItem>
                <ListItemText primary="• Maximum file size: 5MB" />
              </ListItem>
            </List>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );

  const renderReviewStep = () => (
    <Box data-testid="review-step">
      <Typography variant="h6" gutterBottom>
        Review Your Application
      </Typography>
      <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
        Please review your information before submitting.
      </Typography>

      <Grid container spacing={3}>
        <Grid item xs={12} md={8}>
          <Card variant="outlined" sx={{ mb: 2 }}>
            <CardContent>
              <Typography variant="subtitle2" color="text.secondary" gutterBottom>
                Personal Information
              </Typography>
              <Grid container spacing={2}>
                <Grid item xs={6}>
                  <Typography variant="body2" color="text.secondary">First Name</Typography>
                  <Typography data-testid="review-first-name">{formData.firstName}</Typography>
                </Grid>
                <Grid item xs={6}>
                  <Typography variant="body2" color="text.secondary">Last Name</Typography>
                  <Typography data-testid="review-last-name">{formData.lastName}</Typography>
                </Grid>
                <Grid item xs={6}>
                  <Typography variant="body2" color="text.secondary">Date of Birth</Typography>
                  <Typography>{formData.dateOfBirth}</Typography>
                </Grid>
                <Grid item xs={6}>
                  <Typography variant="body2" color="text.secondary">Email</Typography>
                  <Typography>{formData.email}</Typography>
                </Grid>
              </Grid>
            </CardContent>
          </Card>

          <Card variant="outlined" sx={{ mb: 2 }}>
            <CardContent>
              <Typography variant="subtitle2" color="text.secondary" gutterBottom>
                Address
              </Typography>
              <Typography>{formData.street}</Typography>
              <Typography>{formData.city}, {formData.state} {formData.zip}</Typography>
            </CardContent>
          </Card>

          <Card variant="outlined" sx={{ mb: 2 }}>
            <CardContent>
              <Typography variant="subtitle2" color="text.secondary" gutterBottom>
                License Details
              </Typography>
              <Grid container spacing={2}>
                <Grid item xs={6}>
                  <Typography variant="body2" color="text.secondary">License Class</Typography>
                  <Typography>{formData.licenseClass}</Typography>
                </Grid>
                <Grid item xs={6}>
                  <Typography variant="body2" color="text.secondary">Document Number</Typography>
                  <Typography>{formData.documentNumber}</Typography>
                </Grid>
                {formData.restrictions && (
                  <Grid item xs={12}>
                    <Typography variant="body2" color="text.secondary">Restrictions</Typography>
                    <Typography>{formData.restrictions}</Typography>
                  </Grid>
                )}
              </Grid>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} md={4}>
          {formData.portraitPreview && (
            <Card variant="outlined" sx={{ p: 2, textAlign: 'center' }}>
              <Typography variant="subtitle2" color="text.secondary" gutterBottom>
                Portrait Photo
              </Typography>
              <Avatar
                src={formData.portraitPreview}
                sx={{ width: 120, height: 120, mx: 'auto' }}
              />
            </Card>
          )}
        </Grid>

        <Grid item xs={12}>
          <FormControlLabel
            control={
              <Checkbox
                checked={formData.acceptTerms}
                onChange={(e) => setFormData(prev => ({ ...prev, acceptTerms: e.target.checked }))}
                data-testid="accept-terms-checkbox"
              />
            }
            label="I certify that all information provided is accurate and complete. I understand that providing false information may result in denial of my application."
          />
          {validationErrors.acceptTerms && (
            <Typography color="error" variant="caption" display="block">
              {validationErrors.acceptTerms}
            </Typography>
          )}
        </Grid>
      </Grid>
    </Box>
  );

  const renderSubmittedState = () => (
    <Fade in>
      <Box sx={{ textAlign: 'center', py: 6 }} data-testid="application-submitted">
        <CheckCircleIcon sx={{ fontSize: 80, color: 'success.main', mb: 2 }} />
        <Typography variant="h4" gutterBottom>
          Application Submitted!
        </Typography>
        <Typography variant="body1" color="text.secondary" sx={{ mb: 2 }}>
          Your mDL application has been submitted successfully.
        </Typography>

        {applicationId && (
          <Chip
            label={`Application ID: ${applicationId}`}
            color="primary"
            variant="outlined"
            sx={{ mb: 3 }}
            data-testid="application-id"
            data-value={applicationId}
          />
        )}

        <Alert severity="info" sx={{ maxWidth: 400, mx: 'auto', mb: 3 }}>
          You will receive updates on your application status via email. Redirecting to your applications page...
        </Alert>

        <Button
          variant="contained"
          onClick={() => navigate('/my-applications')}
        >
          View My Applications
        </Button>
      </Box>
    </Fade>
  );

  const stepContent = [
    renderPersonalInfoStep,
    renderAddressStep,
    renderLicenseStep,
    renderPhotoStep,
    renderReviewStep,
  ];

  if (submitted) {
    return (
      <Container maxWidth="md" sx={{ py: 4 }}>
        <Paper sx={{ p: 4 }}>
          {renderSubmittedState()}
        </Paper>
      </Container>
    );
  }

  if (configLoading) {
    return (
      <Container maxWidth="md" sx={{ py: 4 }}>
        <Paper sx={{ p: 4, textAlign: 'center' }}>
          <CircularProgress />
        </Paper>
      </Container>
    );
  }

  if (!credentialConfig && !credentialConfigId) {
    return (
      <Container maxWidth="md" sx={{ py: 4 }}>
        <Paper sx={{ p: 4 }}>
          <Alert severity="warning" sx={{ mb: 2 }}>
            Please select a credential from the catalog before starting an application.
          </Alert>
          <Button variant="contained" onClick={() => navigate('/credentials')}>
            Go to Credential Catalog
          </Button>
        </Paper>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" sx={{ py: 4 }} data-testid="credential-application-form">
      {/* Header */}
      <Box sx={{ mb: 4 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, mb: 1 }}>
          <CheckCircleIcon color="primary" fontSize="large" />
          <Typography variant="h4" component="h1">
            {credentialConfig?.display_name || 'Credential Application'}
          </Typography>
        </Box>
        <Typography variant="body1" color="text.secondary">
          Complete the form below to apply for your credential.
        </Typography>
      </Box>

      {/* Stepper */}
      <Paper sx={{ p: 3, mb: 3 }}>
        <Stepper activeStep={activeStep} alternativeLabel>
          {STEPS.map((label) => (
            <Step key={label}>
              <StepLabel>{label}</StepLabel>
            </Step>
          ))}
        </Stepper>
      </Paper>

      {/* Error Alert */}
      {error && (
        <Alert severity="error" sx={{ mb: 3 }} onClose={() => setError(null)}>
          {error}
        </Alert>
      )}

      {/* Form Content */}
      <Paper sx={{ p: 4, mb: 3 }}>
        {stepContent[activeStep]()}
      </Paper>

      {/* Navigation */}
      <Paper sx={{ p: 2 }}>
        <Box sx={{ display: 'flex', justifyContent: 'space-between' }}>
          <Button
            disabled={activeStep === 0}
            onClick={handleBack}
            startIcon={<ArrowBackIcon />}
          >
            Back
          </Button>

          {activeStep < STEPS.length - 1 ? (
            <Button
              variant="contained"
              onClick={handleNext}
              endIcon={<ArrowForwardIcon />}
              data-testid="next-step-btn"
            >
              Next
            </Button>
          ) : (
            <Button
              variant="contained"
              color="success"
              onClick={handleSubmit}
              disabled={submitting}
              endIcon={submitting ? <CircularProgress size={20} /> : <CheckCircleIcon />}
              data-testid="submit-application-btn"
            >
              {submitting ? 'Submitting...' : 'Submit Application'}
            </Button>
          )}
        </Box>
      </Paper>
    </Container>
  );
}
